import{_ as e,o,c as r,an as n}from"./chunks/framework.CTqRDTHW.js";const m=JSON.parse('{"title":"Analysis Report: 011 pgvector Migration + Observability Hardening","description":"","frontmatter":{},"headers":[],"relativePath":"011-vector-setup/analysis-report.md","filePath":"011-vector-setup/analysis-report.md","lastUpdated":1772533348000}'),i={name:"011-vector-setup/analysis-report.md"};function a(d,t,s,c,l,p){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="analysis-report-011-pgvector-migration-observability-hardening" tabindex="-1">Analysis Report: 011 pgvector Migration + Observability Hardening <a class="header-anchor" href="#analysis-report-011-pgvector-migration-observability-hardening" aria-label="Permalink to &quot;Analysis Report: 011 pgvector Migration + Observability Hardening&quot;">​</a></h1><p><strong>Date</strong>: 2026-03-02 <strong>Stage</strong>: Pre-implementation <strong>Auditor</strong>: Claude Code (read-only analysis)</p><hr><h2 id="coverage-matrix-requirements-→-plan-→-tasks" tabindex="-1">Coverage Matrix: Requirements → Plan → Tasks <a class="header-anchor" href="#coverage-matrix-requirements-→-plan-→-tasks" aria-label="Permalink to &quot;Coverage Matrix: Requirements → Plan → Tasks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Req ID</th><th>Title</th><th>Plan Section</th><th>Task IDs</th><th>Status</th></tr></thead><tbody><tr><td>R1</td><td>pgvector Extension</td><td>Target Modules + Technical Context</td><td>TASK-010</td><td>COVERED</td></tr><tr><td>R2</td><td>Sherlock Memory Rewrite</td><td>Technical Context + Architecture</td><td>TASK-020</td><td>COVERED</td></tr><tr><td>R3</td><td>Config Cleanup</td><td>Target Modules</td><td>TASK-021</td><td>COVERED</td></tr><tr><td>R4</td><td>Health Checks</td><td>Risks &amp; Mitigations</td><td>TASK-023, TASK-040, TASK-050</td><td>COVERED</td></tr><tr><td>R5</td><td>SigNoz/OTEL Configuration</td><td>Key Implementation Decisions</td><td>TASK-022, TASK-023</td><td>COVERED</td></tr><tr><td>R6</td><td>Tests</td><td>Project Structure</td><td>TASK-030</td><td>COVERED</td></tr><tr><td>R7</td><td>Contracts + Docs</td><td>Project Structure</td><td>TASK-031, TASK-050, TASK-900</td><td>COVERED</td></tr></tbody></table><p><strong>Coverage Status</strong>: All 7 requirements have corresponding tasks. No orphaned requirements.</p><hr><h2 id="gap-analysis" tabindex="-1">Gap Analysis <a class="header-anchor" href="#gap-analysis" aria-label="Permalink to &quot;Gap Analysis&quot;">​</a></h2><h3 id="_1-blocker-memory-protocol-pattern-not-explicitly-tested" tabindex="-1">1. BLOCKER: Memory Protocol Pattern Not Explicitly Tested <a class="header-anchor" href="#_1-blocker-memory-protocol-pattern-not-explicitly-tested" aria-label="Permalink to &quot;1. BLOCKER: Memory Protocol Pattern Not Explicitly Tested&quot;">​</a></h3><p><strong>Location</strong>: [spec.md] R2, [plan.md] &quot;Memory Protocol (patterns.md §Repository)&quot;, [tasks.md] TASK-001</p><p><strong>Issue</strong>: TASK-001 defines <code>MemoryBackend</code> Protocol extraction, but:</p><ul><li>No explicit test is specified for the protocol itself</li><li>TASK-030 (test_memory.py rewrite) doesn&#39;t mention protocol compliance testing</li><li>patterns.md §2 (Repository Pattern) states interfaces must be domain-specific — unclear if &quot;memory backend interface&quot; is explicit enough for type safety verification</li></ul><p><strong>Risk</strong>: Protocol extraction may not be validated, leaving future backends (Redis, Weaviate) without type safety guarantees.</p><p><strong>Recommendation</strong>: Add acceptance criterion to TASK-030: &quot;Protocol conformance verified via <code>mypy --strict</code> on <code>SherlockMemory</code> class — all methods match signature&quot;</p><hr><h3 id="_2-blocker-asyncpg-vector-codec-event-hook-—-no-coverage-in-dev-startup" tabindex="-1">2. BLOCKER: asyncpg Vector Codec Event Hook — No Coverage in Dev Startup <a class="header-anchor" href="#_2-blocker-asyncpg-vector-codec-event-hook-—-no-coverage-in-dev-startup" aria-label="Permalink to &quot;2. BLOCKER: asyncpg Vector Codec Event Hook — No Coverage in Dev Startup&quot;">​</a></h3><p><strong>Location</strong>: [plan.md] &quot;asyncpg + pgvector type registration&quot; (lines 120–134)</p><p><strong>Issue</strong>: The plan correctly identifies that <code>register_vector</code> must be called via a SQLAlchemy <code>connect</code> event. However:</p><ul><li>TASK-020 acceptance criteria state the hook must be &quot;tested in test_memory.py&quot;</li><li>But <strong>no guidance on testing the event hook itself</strong> — SQLAlchemy event registration is async/connection-scoped and notoriously hard to mock</li><li>TASK-040 integration test doesn&#39;t explicitly verify the hook works end-to-end (e.g., actual vector round-trip)</li><li>If the event hook fails silently, the UpsertTypeError only appears at runtime in <code>make dev</code>, not in <code>make reasoner-test</code></li></ul><p><strong>Recommendation</strong>:</p><ul><li>TASK-020: Add acceptance criterion: &quot;Integration test with real async engine + pgvector connection confirms vector codec loads (insert &amp; retrieve vector column)&quot;</li><li>TASK-040: Add explicit vector round-trip test in end-to-end acceptance: &quot;Search returns context with embedding distance ordering verified&quot;</li></ul><hr><h3 id="_3-blocker-otel-environment-variables-—-conflicting-endpoint-urls" tabindex="-1">3. BLOCKER: OTEL Environment Variables — Conflicting Endpoint URLs <a class="header-anchor" href="#_3-blocker-otel-environment-variables-—-conflicting-endpoint-urls" aria-label="Permalink to &quot;3. BLOCKER: OTEL Environment Variables — Conflicting Endpoint URLs&quot;">​</a></h3><p><strong>Location</strong>: [plan.md] line 173, [tasks.md] TASK-022 and TASK-023</p><p><strong>Issue</strong>: Plan states:</p><ul><li>&quot;Use <code>127.0.0.1:4317</code> for local binary runs (not <code>localhost</code> — IPv6 resolution issue on macOS with Docker Desktop)&quot;</li><li>&quot;Docker Compose uses service DNS so <code>arc-friday-collector:4317</code> is correct inside containers&quot;</li></ul><p>But [tasks.md] acceptance criteria for TASK-022 and TASK-023 do <strong>not</strong> specify which endpoint to use:</p><ul><li>Line 69 (TASK-022): &quot;All 9 OTEL_* env vars present&quot; — doesn&#39;t specify endpoint value</li><li>Line 74 (TASK-023): Same — no guidance on endpoint choice for Sherlock&#39;s compose</li></ul><p><strong>Risk</strong>: Developers may hardcode <code>localhost:4317</code> in docker-compose.yml, breaking OTEL collection in containers; or use <code>127.0.0.1:4317</code> in compose, breaking local binary runs.</p><p><strong>Recommendation</strong>: Update acceptance criteria:</p><ul><li>TASK-022: <code>OTEL_EXPORTER_OTLP_ENDPOINT</code> MUST be <code>http://arc-friday-collector:4317</code> (service DNS name, not localhost/127.0.0.1)</li><li>TASK-023: Same as TASK-022</li><li>Add comment in docker-compose.yml: <code># Use service DNS name inside containers; for local binary runs, override with OTEL_EXPORTER_OTLP_ENDPOINT=127.0.0.1:4317</code></li></ul><hr><h3 id="_4-warning-missing-verify-no-qdrant-imports-task" tabindex="-1">4. WARNING: Missing Verify-No-Qdrant-Imports Task <a class="header-anchor" href="#_4-warning-missing-verify-no-qdrant-imports-task" aria-label="Permalink to &quot;4. WARNING: Missing Verify-No-Qdrant-Imports Task&quot;">​</a></h3><p><strong>Location</strong>: [tasks.md] TASK-020 acceptance criteria</p><p><strong>Issue</strong>: TASK-020 acceptance states &quot;All <code>qdrant_client</code> imports removed&quot; and <code>ruff check</code> + <code>mypy</code> pass. However:</p><ul><li>No explicit acceptance criterion for &quot;grep/rg confirms zero <code>qdrant</code> mentions in source tree&quot;</li><li>TASK-999 (Reviewer) does mention &quot;zero Qdrant imports in source&quot; — but this should be verified during implementation, not just review</li></ul><p><strong>Recommendation</strong>: Add to TASK-020 acceptance: &quot;Verify no stray <code>qdrant</code> imports: <code>rg &#39;qdrant&#39; services/reasoner/src/ --type py</code> returns zero matches&quot;</p><hr><h3 id="_5-warning-sentence-transformer-model-download-not-addressed-in-health-check" tabindex="-1">5. WARNING: Sentence-Transformer Model Download Not Addressed in Health Check <a class="header-anchor" href="#_5-warning-sentence-transformer-model-download-not-addressed-in-health-check" aria-label="Permalink to &quot;5. WARNING: Sentence-Transformer Model Download Not Addressed in Health Check&quot;">​</a></h3><p><strong>Location</strong>: [plan.md] Risks § &quot;Sentence-transformer model download on cold start&quot; (L222)</p><p><strong>Issue</strong>: Risk mitigation states &quot;start_period: 60s in healthcheck gives model time to load&quot;. However:</p><ul><li>[spec.md] R4 specifies only <code>/health/deep</code> with no mention of retry logic or lazy initialization</li><li>If model download takes &gt;60s, healthcheck fails and <code>depends_on</code> sees failed status before LangGraph initializes</li><li>No acceptance criterion in TASK-023 or TASK-040 validates model pre-loading or healthcheck behavior under slow network</li></ul><p><strong>Recommendation</strong>: Add to TASK-023 acceptance: &quot;Healthcheck <code>start_period: 60s</code> confirmed; test with simulated slow model download shows service enters healthy state without timeout&quot;</p><hr><h3 id="_6-warning-hnsw-index-idempotency-not-explicitly-tested" tabindex="-1">6. WARNING: HNSW Index Idempotency Not Explicitly Tested <a class="header-anchor" href="#_6-warning-hnsw-index-idempotency-not-explicitly-tested" aria-label="Permalink to &quot;6. WARNING: HNSW Index Idempotency Not Explicitly Tested&quot;">​</a></h3><p><strong>Location</strong>: [plan.md] Risks § &quot;HNSW index creation fails on empty table&quot; (L219)</p><p><strong>Issue</strong>: Risk states &quot;CREATE INDEX IF NOT EXISTS is idempotent; HNSW works on 0 rows&quot;. However:</p><ul><li>TASK-020 acceptance states &quot;creates HNSW index&quot; but doesn&#39;t specify idempotency testing</li><li>TASK-030 (test_memory.py) doesn&#39;t mention verifying <code>init()</code> can be called twice without error</li><li>TASK-040 runs <code>make dev</code> once; no re-initialization test</li></ul><p><strong>Recommendation</strong>: Add to TASK-030 acceptance: &quot;Test <code>SherlockMemory.init()</code> called twice on same schema — no <code>CREATE INDEX ... ALREADY EXISTS</code> error (idempotency verified)&quot;</p><hr><h3 id="_7-warning-missing-cortex-service-verification-in-integration-test" tabindex="-1">7. WARNING: Missing Cortex Service Verification in Integration Test <a class="header-anchor" href="#_7-warning-missing-cortex-service-verification-in-integration-test" aria-label="Permalink to &quot;7. WARNING: Missing Cortex Service Verification in Integration Test&quot;">​</a></h3><p><strong>Location</strong>: [tasks.md] TASK-040 acceptance criteria</p><p><strong>Issue</strong>: Integration test verifies Sherlock (<code>curl localhost:8083/chat</code>) but does <strong>not</strong> verify Cortex health or OTEL visibility:</p><ul><li>No <code>curl localhost:CORTEX_PORT/health</code> check</li><li>No verification that SigNoz UI shows Cortex service metadata</li><li>TASK-999 (Reviewer) mentions &quot;Cortex visible with service.namespace=arc-platform&quot; — but this is a review checklist, not a dev acceptance criterion</li></ul><p><strong>Recommendation</strong>: Add to TASK-040 acceptance: &quot;Cortex health endpoint returns 200 OK; SigNoz UI (if <code>reason</code> profile) shows Cortex with <code>service.namespace=arc-platform</code> tag&quot;</p><hr><h3 id="_8-info-profiles-yaml-still-references-vector-db" tabindex="-1">8. INFO: Profiles.yaml Still References <code>vector-db</code> <a class="header-anchor" href="#_8-info-profiles-yaml-still-references-vector-db" aria-label="Permalink to &quot;8. INFO: Profiles.yaml Still References `vector-db`&quot;">​</a></h3><p><strong>Location</strong>: [services/profiles.yaml] line 15, [tasks.md] TASK-040</p><p><strong>Issue</strong>: Current profiles.yaml shows <code>vector-db</code> in <code>think</code> profile (VERIFIED DURING AUDIT). TASK-040 acceptance correctly removes it, but:</p><ul><li>No task explicitly removes <code>vector-db</code> from the <code>reason</code> or <code>ultra-instinct</code> profiles (if present)</li><li>[plan.md] only mentions removal from <code>think</code></li><li>[spec.md] R1 only states &quot;removed from the <code>think</code> profile&quot;</li></ul><p><strong>Status</strong>: Compliant with spec — removal from <code>think</code> is sufficient. Noted for completeness.</p><hr><h2 id="risks-assessment" tabindex="-1">Risks Assessment <a class="header-anchor" href="#risks-assessment" aria-label="Permalink to &quot;Risks Assessment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk ID</th><th>Risk</th><th>Severity</th><th>Mitigation</th><th>Status</th></tr></thead><tbody><tr><td>R1</td><td>asyncpg vector codec not registered</td><td>HIGH</td><td>Event hook in <code>__init__</code> + integration test</td><td>MITIGATED (see Gap #2)</td></tr><tr><td>R2</td><td>OTEL endpoint misconfigured in compose</td><td>HIGH</td><td>Clear endpoint value in acceptance criteria</td><td>MITIGATED (see Gap #3)</td></tr><tr><td>R3</td><td>Qdrant imports not fully removed</td><td>MEDIUM</td><td>Grep verification in acceptance</td><td>MITIGATED (see Gap #4)</td></tr><tr><td>R4</td><td>Model download exceeds healthcheck timeout</td><td>MEDIUM</td><td><code>start_period: 60s</code> confirmed</td><td>MITIGATED (see Gap #5)</td></tr><tr><td>R5</td><td>HNSW index creation not idempotent</td><td>LOW</td><td><code>CREATE INDEX IF NOT EXISTS</code> + test twice</td><td>MITIGATED (see Gap #6)</td></tr><tr><td>R6</td><td>Existing Qdrant data not migrated</td><td>LOW</td><td>Dev env only; fresh start acceptable</td><td>DOCUMENTED (plan.md L220)</td></tr><tr><td>R7</td><td>pgvector image not in cache</td><td>MEDIUM</td><td>CI pre-pull; first run pulls from Docker Hub</td><td>DOCUMENTED (plan.md L221)</td></tr></tbody></table><hr><h2 id="parallel-execution-analysis" tabindex="-1">Parallel Execution Analysis <a class="header-anchor" href="#parallel-execution-analysis" aria-label="Permalink to &quot;Parallel Execution Analysis&quot;">​</a></h2><p><strong>Current Task DAG Review</strong>:</p><p>Marked as <code>[P]</code> (parallel-safe):</p><ul><li>TASK-001 (MemoryBackend Protocol) — SAFE</li><li>TASK-010 (Persistence image) — SAFE (no overlap with reasoner)</li><li>TASK-022 (Cortex OTEL) — SAFE (isolated compose)</li><li>TASK-023 (Sherlock OTEL + healthcheck) — <strong>UNSAFE</strong> — depends on TASK-001 not specified but required for proper memory protocol testing; recommend explicit dependency</li></ul><p>Marked as dependent but could parallelize:</p><ul><li>TASK-020 (memory.py rewrite) depends on TASK-001 — CORRECT (Protocol must exist first)</li><li>TASK-021 (Config cleanup) depends on TASK-001 — COULD BE PARALLEL to TASK-020 (independent cleanup); dependency is implicit but reasonable</li><li>TASK-030 (test rewrite) depends on TASK-020 — CORRECT</li><li>TASK-031 (health key cleanup) depends on TASK-020 — CORRECT</li></ul><p><strong>Recommendation</strong>: Verify that TASK-023 can truly start independently; if Docker healthcheck block needs to be aware of memory protocol, add explicit <code>TASK-001 → TASK-023</code> dependency.</p><hr><h2 id="constitution-compliance" tabindex="-1">Constitution Compliance <a class="header-anchor" href="#constitution-compliance" aria-label="Permalink to &quot;Constitution Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Applies</th><th>Status</th><th>Evidence</th></tr></thead><tbody><tr><td>I. Zero-Dependency CLI</td><td>N/A</td><td>N/A</td><td>No CLI changes</td></tr><tr><td>II. Platform-in-a-Box</td><td>REQUIRED</td><td>PASS</td><td>Single <code>docker compose up</code> still works; <code>think</code> profile simplified</td></tr><tr><td>III. Modular Services</td><td>REQUIRED</td><td>PASS</td><td>Each service (persistence, reasoner) self-contained; profiles.yaml updated cleanly</td></tr><tr><td>IV. Two-Brain Separation</td><td>REQUIRED</td><td>PASS</td><td>All changes Python (intelligence) + SQL (infra); no Go logic in Python code</td></tr><tr><td>V. Polyglot Standards</td><td>REQUIRED</td><td>PASS</td><td>Python: ruff + mypy enforced; 12-Factor config; async/await patterns correct; OTEL env vars standard</td></tr><tr><td>VI. Local-First</td><td>N/A</td><td>N/A</td><td>No CLI changes</td></tr><tr><td>VII. Observability by Default</td><td>REQUIRED</td><td>PASS</td><td>Full OTEL instrumentation wired for Sherlock + Cortex; SigNoz pre-configured; health checks added</td></tr><tr><td>VIII. Security by Default</td><td>REQUIRED</td><td>PASS</td><td>Non-root containers unchanged; no secrets in config; pgvector adds no new attack surface</td></tr><tr><td>IX. Declarative Reconciliation</td><td>N/A</td><td>N/A</td><td>No CLI changes</td></tr><tr><td>X. Stateful Operations</td><td>N/A</td><td>N/A</td><td>No CLI changes</td></tr><tr><td>XI. Resilience Testing</td><td>REQUIRED</td><td>PASS</td><td>Single-store eliminates dual-write failure mode; health checks added; HNSW index resilient to empty table</td></tr><tr><td>XII. Interactive Experience</td><td>N/A</td><td>N/A</td><td>No CLI changes</td></tr></tbody></table><p><strong>Overall Constitution Status</strong>: 6 PASS, 6 N/A. No violations detected.</p><hr><h2 id="patterns-md-compliance" tabindex="-1">Patterns.md Compliance <a class="header-anchor" href="#patterns-md-compliance" aria-label="Permalink to &quot;Patterns.md Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Applies</th><th>Status</th><th>Evidence</th></tr></thead><tbody><tr><td>Factory/DI</td><td>REQUIRED (Python)</td><td>PASS</td><td><code>SherlockMemory</code> accepts engine + logger via <strong>init</strong>; no globals</td></tr><tr><td>Repository</td><td>REQUIRED (Python)</td><td>PASS</td><td><code>MemoryBackend</code> Protocol defined; <code>SherlockMemory</code> implements domain-specific methods (search, save, health_check)</td></tr><tr><td>Config Precedence</td><td>REQUIRED (Python)</td><td>PASS</td><td>Config cleanup removes hard-coded qdrant_* settings; OTEL via 12-Factor env vars</td></tr><tr><td>Error Handling</td><td>REQUIRED</td><td>PASS</td><td>Async errors from pgvector wrapped; no silent failures</td></tr><tr><td>Testing Standards</td><td>REQUIRED</td><td>PASS</td><td>pytest async tests; mocks at SQLAlchemy boundary only; coverage targets 75% critical</td></tr><tr><td>XDG Base Directory</td><td>N/A</td><td>N/A</td><td>Applies to CLI only</td></tr><tr><td>Observability Pattern (Go)</td><td>N/A</td><td>N/A</td><td>No Go service logic changes</td></tr></tbody></table><p><strong>Overall Patterns Status</strong>: 5 PASS, 2 N/A. No violations.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><strong>Blockers</strong>: 3 (memory protocol testing, OTEL endpoint clarity, asyncpg codec coverage) <strong>Warnings</strong>: 5 (no-qdrant-imports verification, model download health check, HNSW idempotency, Cortex verification, parallel safety of TASK-023) <strong>Observations</strong>: 1 (vector-db removal already compliant with spec intent)</p><h3 id="recommendation" tabindex="-1">Recommendation <a class="header-anchor" href="#recommendation" aria-label="Permalink to &quot;Recommendation&quot;">​</a></h3><p><strong>PAUSE TO FIX BLOCKERS</strong></p><p>The spec and plan are well-structured, but three critical issues must be resolved before implementation begins:</p><ol><li><strong>Clarify TASK-020 acceptance</strong> to explicitly verify asyncpg vector codec works end-to-end (not just code presence)</li><li><strong>Specify exact OTEL endpoint values</strong> in TASK-022 and TASK-023 acceptance criteria (<code>arc-friday-collector:4317</code> inside compose; document override for local binary)</li><li><strong>Add integration test to TASK-040</strong> verifying actual vector round-trip through pgvector (save + search + verify ordering by distance)</li></ol><p>Once these are addressed, all 7 requirements map cleanly to 12 tasks with safe parallelism. No constitution violations detected. Ready for implementation after blockers resolved.</p><hr><p><strong>Audit Complete</strong>: 2026-03-02 16:00 UTC</p>',90)])])}const u=e(i,[["render",a]]);export{m as __pageData,u as default};
